	ToggleTagBudget(context.Context, *MsgToggleTagBudget) (*MsgToggleTagBudgetResponse, error)
	// WithdrawTagBudget defines the WithdrawTagBudget RPC.
	WithdrawTagBudget(context.Context, *MsgWithdrawTagBudget) (*MsgWithdrawTagBudgetResponse, error)
	// BondSentinel defines the BondSentinel RPC. Stakes DREAM to register
	// as an accountable sentinel across all content modules.
	BondSentinel(context.Context, *MsgBondSentinel) (*MsgBondSentinelResponse, error)
	// UnbondSentinel defines the UnbondSentinel RPC. Withdraws sentinel
	// bond (subject to committed/pending-action constraints).
	UnbondSentinel(context.Context, *MsgUnbondSentinel) (*MsgUnbondSentinelResponse, error)
	// ReportMember defines the ReportMember RPC.
	ReportMember(context.Context, *MsgReportMember) (*MsgReportMemberResponse, error)
